### з≠Фж°И

$$\displaystyle\left(\sum^l_{1\le l\le n}\sum^i_{1\le i\le m}\sum^j_{i\le j\le m}dp_{l,i,j}\right)\bmod{10^9+7}$$

```cpp
#include<bits/stdc++.h>
typedef int int32;
#define int long long
using namespace std;
const int N = 100 + 5;
int n, m, dp[N][N][N], sum[N][N], vis[N][N], ans, mod = 1e9 + 7;
signed main()
{
	ios::sync_with_stdio(0);
	cin.tie(0), cout.tie(0);
	cin >> n >> m;
	for (int i = n; i >= 1; i--)
		for (int j = 1; j <= m; j++)
		{
			char c;
			cin >> c;
			vis[i][j] = vis[i][j - 1] + (c == 'X');
		}
	dp[0][1][m] = 1;
	for (int l = 1; l <= n; l++)
	{
		memset(sum, 0, sizeof sum);
		for (int i = 1; i <= m; i++)
			for (int j = i; j <= m; j++)
				sum[i][j] = (sum[i - 1][j] + sum[i][j - 1] - sum[i - 1][j - 1] +
					dp[l - 1][i][j] + mod) % mod;
		for (int len = 1; len <= m; len++)
			for (int i = 1; i + len - 1 <= m; i++)
			{
				int j = i + len - 1;
				if (!(vis[l][j] - vis[l][i - 1]))
					ans = (ans + (dp[l][i][j] = (sum[i][m] - sum[i][j - 1] +
						mod) % mod)) % mod;
			}
	}
	cout << (ans + 1) % mod;
	return 0;
}
```

